import React, { useEffect, useState } from 'react';
import { routeOptimizationService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function RouteOptimization() {
  const [loading, setLoading] = useState(true);
  const [routes, setRoutes] = useState([]);
  const [selectedRoute, setSelectedRoute] = useState(null);
  const [optimizing, setOptimizing] = useState(false);

  useEffect(() => {
    loadRoutes();
  }, []);

  const loadRoutes = async () => {
    try {
      const data = await routeOptimizationService.getRoutes();
      setRoutes(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleOptimize = async (route) => {
    setOptimizing(true);
    try {
      const optimized = await routeOptimizationService.optimizeRoute(route.vehicle_id, route.stops);
      setSelectedRoute({
        original: route,
        optimized: optimized,
        improvement: Math.round(((route.distance - optimized.estimatedDistanceKm) / route.distance) * 100)
      });
    } catch (err) {
      console.error(err);
    } finally {
      setOptimizing(false);
    }
  };

  return (
    <div className="page-header">
      <div>
        <h1 className="page-title">🚚 Route Optimization</h1>
        <p className="page-subtitle">Real-time spatial computation and AI-driven efficiency</p>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : (
          <div className="grid grid-2">
            {/* Routes List */}
            <div>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">Active Routes</div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                  {routes.map((route, idx) => (
                    <div
                      key={idx}
                      className="card interactive"
                      onClick={() => setSelectedRoute({ original: route })}
                      style={{
                        cursor: 'pointer',
                        borderColor: selectedRoute?.original?.id === route.id ? '#00ff88' : 'rgba(0, 255, 136, 0.1)'
                      }}
                    >
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                        <div>
                          <div style={{ fontWeight: '600' }}>Vehicle #{route.vehicle_id}</div>
                          <div style={{ fontSize: '12px', color: '#a0b0c0', marginTop: '4px' }}>
                            🗺️ {route.stops.length} stops • {route.distance.toFixed(1)} km
                          </div>
                        </div>
                        <button 
                          className="btn btn-accent btn-sm"
                          onClick={() => handleOptimize(route)}
                          disabled={optimizing}
                        >
                          ⚡ Optimize
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Route Comparison */}
            {selectedRoute && (
              <div className="card">
                <div className="card-header">
                  <div className="card-title">
                    {selectedRoute.improvement 
                      ? `Route Analysis - ${selectedRoute.improvement}% Improved` 
                      : 'Route Details'}
                  </div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  {/* Original Route */}
                  <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                    <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase' }}>Standard Protocol (Legacy)</div>
                    <div style={{ marginTop: '8px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                      <div>
                        <div style={{ fontSize: '24px', fontWeight: '700' }}>
                          {selectedRoute.original.distance.toFixed(1)} km
                        </div>
                        <div style={{ fontSize: '12px', color: '#a0b0c0' }}>Total Distance</div>
                      </div>
                      <div>
                        <div style={{ fontSize: '24px', fontWeight: '700' }}>
                          {Math.round((selectedRoute.original.distance / 25) * 60)} min
                        </div>
                        <div style={{ fontSize: '12px', color: '#a0b0c0' }}>Est. Duration</div>
                      </div>
                    </div>
                  </div>

                  {/* Optimized Route */}
                  {selectedRoute.optimized && (
                    <div style={{ padding: '12px', background: 'rgba(0, 255, 136, 0.1)', borderRadius: '8px', border: '1px solid rgba(0, 255, 136, 0.3)' }}>
                      <div style={{ fontSize: '12px', color: '#00ff88', textTransform: 'uppercase', fontWeight: '600' }}>⚡ EcoFlow AI Optimized</div>
                      <div style={{ marginTop: '8px', display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
                        <div>
                          <div style={{ fontSize: '24px', fontWeight: '700', color: '#00ff88' }}>
                            {selectedRoute.optimized.estimatedDistanceKm.toFixed(1)} km
                          </div>
                          <div style={{ fontSize: '12px', color: '#a0b0c0' }}>Total Distance</div>
                        </div>
                        <div>
                          <div style={{ fontSize: '24px', fontWeight: '700', color: '#00ff88' }}>
                            {selectedRoute.optimized.estimatedDurationMin} min
                          </div>
                          <div style={{ fontSize: '12px', color: '#a0b0c0' }}>Est. Duration</div>
                        </div>
                        <div>
                          <div style={{ fontSize: '24px', fontWeight: '700', color: '#00ff88' }}>
                            {selectedRoute.improvement}%
                          </div>
                          <div style={{ fontSize: '12px', color: '#a0b0c0' }}>Improvement</div>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Capacity */}
                  <div>
                    <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '8px' }}>Capacity Utilization</div>
                    <div style={{ height: '8px', background: 'rgba(0, 255, 136, 0.1)', borderRadius: '4px', overflow: 'hidden' }}>
                      <div 
                        style={{
                          height: '100%',
                          background: 'linear-gradient(90deg, #11998e, #38ef7d)',
                          width: '85%',
                          transition: 'width 0.3s'
                        }}
                      />
                    </div>
                    <div style={{ fontSize: '12px', marginTop: '4px', textAlign: 'right', color: '#a0b0c0' }}>85% capacity</div>
                  </div>

                  <button className="btn btn-accent" style={{ width: '100%' }}>
                    ✓ Apply Optimized Route
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default RouteOptimization;
